import tensorflow as tf# 数据集预处理(train_xs, train_ys), (test_xs, test_ys) = tf.keras.datasets.mnist.load_data()      # 加载数据集print('train_datasets:', train_xs.shape, train_ys.shape)train_xs = tf.convert_to_tensor(train_xs, dtype=tf.float32) / 255.                  # 数据标准化train_db = tf.data.Dataset.from_tensor_slices((train_xs, train_ys)).batch(100)      # 切分数据# 定义模型class Model(object):    def __init__(self):        # 隐藏层 1        self.w1 = tf.Variable(tf.random.truncated_normal([784, 256], stddev=0.1))        self.b1 = tf.Variable(tf.zeros([256]))        # 隐藏层 2        self.w2 = tf.Variable(tf.random.truncated_normal([256, 128], stddev=0.1))        self.b2 = tf.Variable(tf.zeros([128]))        # 隐藏层 3        self.w3 = tf.Variable(tf.random.truncated_normal([128, 64], stddev=0.1))        self.b3 = tf.Variable(tf.zeros([64]))        # 输出层张量        self.w4 = tf.Variable(tf.random.truncated_normal([64, 10], stddev=0.1))        self.b4 = tf.Variable(tf.zeros([10]))    def __call__(self, inputs):        # x: [b, 28*28]        # 隐藏层 1 前向计算， [b, 28*28] => [b, 256]        h1 = inputs @ self.w1 + self.b1        h1 = tf.nn.relu(h1)        # 隐藏层 2 前向计算， [b, 256] => [b, 128]        h2 = h1 @ self.w2 + self.b2        h2 = tf.nn.relu(h2)        # 隐藏层 3 前向计算， [b, 128] => [b, 64]        h3 = h2 @ self.w3 + self.b3        h3 = tf.nn.relu(h3)        # 输出层前向计算， [b, 64] => [b, 10]        h4 = h3 @ self.w4 + self.b4        h4 = tf.nn.softmax(h4)        return h4# 定义损失函数def compute_loss(y_true, y_pred):    return tf.reduce_mean(tf.losses.categorical_crossentropy(y_true, y_pred))  # 计算交叉熵损失函数learn_rate = 0.2   # 学习率epoch = 5          # 训练轮数model = Model()    # 定义模型loss_buf = []      # 存储每一个批次的损失值for i in range(0, epoch):    print("===============第{}轮===============".format(i + 1))    for step, (x, y) in enumerate(train_db):        with tf.GradientTape() as tape:            x = tf.reshape(x, (-1, 28 * 28))       # 打平操作，[b, 28, 28] => [b, 784]            y_pred = model(x)                      # 获取预测值            y_onehot = tf.one_hot(y, depth=10)     # 将实际值转化为one_hot编码            loss = compute_loss(y_onehot, y_pred)  # 计算误差        grad = tape.gradient(loss, [model.w1, model.b1, model.w2, model.b2,                                    model.w3, model.b3, model.w4, model.b4])        model.w1.assign_sub(learn_rate * grad[0])        model.b1.assign_sub(learn_rate * grad[1])        model.w2.assign_sub(learn_rate * grad[2])        model.b2.assign_sub(learn_rate * grad[3])        model.w3.assign_sub(learn_rate * grad[4])        model.b3.assign_sub(learn_rate * grad[5])        model.w4.assign_sub(learn_rate * grad[6])        model.b4.assign_sub(learn_rate * grad[7])        correct_prediction = tf.equal(tf.argmax(y_pred, 1), tf.argmax(y_onehot, 1))        # 准确率，将布尔值转化为浮点数，并计算平均值        accuracy = tf.reduce_mean(tf.cast(correct_prediction, tf.float32))        if step % 10 == 0:            print(step, 'loss:', float(loss), 'acc:', accuracy.numpy())